// Mapa: shot id -> { prompt, duration, genre, resolution }
// Zsynchronizuj z ../PROMPTY.md gdy zmieniasz prompty.
const PROMPTS = {
  'r1-01': { prompt: 'Slow cinematic dolly-in from 2 meters to 0.5 meters toward an industrial DTF printer on a dark background. Soft rim light from the right. Subtle dust particles drifting in the beam. Camera glides smoothly, no shake. Realistic, hyper-detailed, cinematic depth of field.', duration: 5, genre: 'drama', resolution: '720p' },
  'r1-02': { prompt: 'Top-down camera tilts down 30 degrees to reveal the inside of an open industrial printer. Internal LED light glows soft blue. Mechanical rails are sharply in focus, the background falls into bokeh. Smooth gimbal-like motion. Photorealistic.', duration: 5, genre: 'drama', resolution: '720p' },
  'r1-03': { prompt: 'Overhead drone-style camera slowly pushes down toward a printer seen from directly above. The machine sits in a clean studio. Light catches the metal edges. Realistic, sharp focus, no warping of mechanical parts.', duration: 4, genre: 'auto', resolution: '720p' },
  'r1-04': { prompt: 'Extreme close-up macro of a printer print head. Camera slowly pans 5cm to the right along the row of nozzles, holding the nozzle line in razor-sharp focus. Tiny reflections on metal. Subtle ink residue. No motion of the head itself. Hyper-realistic macro photography style.', duration: 5, genre: 'auto', resolution: '1080p' },
  'r1-05': { prompt: 'Macro close-up of a printer print head seen from the side. Camera holds still while the print head slowly slides 3cm to the left along its rail. Mechanical wires and cables visible in the background, slightly out of focus. Cool industrial lighting.', duration: 4, genre: 'auto', resolution: '720p' },
  'r1-06': { prompt: 'Macro shot of a printer print head in motion, moving rapidly back and forth along a metal rail. Camera holds steady. Light motion blur on the head. Sharp focus on the rail and surroundings. Industrial workshop atmosphere.', duration: 4, genre: 'auto', resolution: '720p' },
  'r1-07': { prompt: 'Extreme macro slow-motion of a single black ink droplet falling and impacting a white surface. The droplet stretches, splashes, then settles. 240fps slow-motion feel. Crystal sharp focus on the droplet. Black void background. Hyper-realistic, food-photography style lighting.', duration: 4, genre: 'drama', resolution: '1080p' },
  'r1-08': { prompt: 'Slow turntable rotation of an ink bottle on a black reflective surface. Camera holds steady, the bottle rotates 30 degrees. Soft side light creates a long highlight on the bottle curve. Photo-realistic product commercial style.', duration: 4, genre: 'auto', resolution: '720p' },
  'r1-09': { prompt: 'Cinematic macro slow-motion of black liquid pouring from a bottle into a cartridge. The liquid stream is smooth, glossy, no splashing. Camera holds at eye-level with the stream. Soft rim light catches the surface tension. Crystal sharp.', duration: 5, genre: 'drama', resolution: '1080p' },
  'r1-10': { prompt: 'Slow camera glide across a printed DTF transfer film, revealing vivid colors and crisp detail. Camera moves left-to-right at 3cm per second, 10cm above the surface. Sharp focus on the print, soft light from above. Product showcase aesthetic.', duration: 5, genre: 'auto', resolution: '720p' },
  'r1-11': { prompt: 'Steam rising slowly from a heat press while a printed transfer is applied to a t-shirt. Camera holds at a low angle. The steam catches a soft warm backlight. No people in frame. Cinematic industrial atmosphere.', duration: 5, genre: 'drama', resolution: '720p' },
  'r1-12': { prompt: 'Slow push-in macro across a vibrant printed pattern on textile. Threads visible. Camera moves 2cm forward. Crisp light, color-rich. Final product showcase shot, satisfying reveal.', duration: 4, genre: 'epic', resolution: '720p' }
};

const shots = $input.first().json.shots || [];
return shots.map(s => ({
  json: {
    shot_id: s.id,
    image_url: s.image_url,
    ...(PROMPTS[s.id] || { prompt: 'Slow cinematic camera move, photorealistic, no distortion of mechanical parts.', duration: 4, genre: 'auto', resolution: '720p' })
  }
}));
